const results = [];
try {
  const r0 = $('Check: WF-301 SEO Content').first().json;
  const last = (r0.data||[])[0];
  if (!last) results.push({ name: 'WF-301 SEO Content', status: 'no_runs', ok: false });
  else {
    const ageH = Math.round((Date.now() - new Date(last.stoppedAt||last.startedAt).getTime())/3600000);
    results.push({ name: 'WF-301 SEO Content', status: last.status, age: ageH, ok: last.status === 'success' });
  }
} catch(e) { results.push({ name: 'WF-301 SEO Content', status: 'error', ok: false }); }
