const errors = results.filter(r => !r.ok);
const ok = results.filter(r => r.ok);

const msk = new Date(Date.now() + 3*3600000);
const t = msk.toLocaleTimeString('ru-RU',{timeZone:'UTC',hour:'2-digit',minute:'2-digit'});

let msg;
if (errors.length === 0) {
  msg = `✅ Все воркфлоу OK (${t} MSK)\n` + ok.map(r=>`  ✅ ${r.name} (${r.age}ч назад)`).join('\n');
} else {
  msg = `🚨 АЛЕРТ: ${errors.length} проблем (${t} MSK)\n\n`;
  msg += errors.map(r=>`❌ ${r.name}: ${r.status}${r.age?' ('+r.age+'ч назад)':''}`).join('\n');
  msg += '\n\n✅ Работают:\n' + ok.map(r=>`  ${r.name} (${r.age}ч)`).join('\n');
}

return [{ json: { text: msg, has_errors: errors.length > 0 } }];
